<template>
  <div>
    <v-col lg="10" xl="8" class="mx-auto">
      <h1 class="mb-5">Compare Pokemons</h1>
      <v-data-table
        v-model="selected"
        :headers="headers"
        :items="statsOnlyCompareList"
        item-key="image"
        :multi-sort="true"
        :single-select="false"
        show-select
        class="elevation-1"
      >
        <template v-slot:item.total="{ item }">
          <v-chip :color="getTotalColor(item.total)" class="px-5" dark>{{
            item.total
          }}</v-chip>
        </template>
        <template v-slot:item.image="{ item }">
          <v-img
            class="white--text align-end ma-2"
            contain
            :src="
              `https://pokeres.bastionbot.org/images/pokemon/${item.image}.png`
            "
            :lazy-src="
              `https://pokeres.bastionbot.org/images/pokemon/${item.image}.png`
            "
            :alt="item.name"
            width="100px"
          >
          </v-img>
        </template>
      </v-data-table>
      <v-btn
        color="error"
        class="my-5"
        :disabled="!isRemovable"
        @click="removeSelectedPokemons"
      >
        Remove selected pokemons
      </v-btn>
      <v-card elevation="5">
        <v-card-title>Radar Chart</v-card-title>
        <v-divider></v-divider>
        <v-card-text>
          <radar-chart
            :chart-data="chartData"
            :options="chartOptions"
          ></radar-chart
        ></v-card-text>
      </v-card>
    </v-col>
  </div>
</template>

<script>
import { mapState, mapGetters } from "vuex";
import RadarChart from "@/components/RadarChart.vue";

export default {
  components: {
    RadarChart,
  },
  computed: {
    ...mapState(["comparePokemons", "isDark"]),
    isRemovable() {
      return this.selected.length > 0;
    },
    statsOnlyCompareList() {
      return this.comparePokemons.map((item) => {
        var obj = { name: item.name, image: item.id, id: item.id };
        var total = 0;
        item.stats.forEach((stat) => {
          obj[stat.name] = stat.baseStat;
          total += stat.baseStat;
        });
        return { ...obj, total };
      });
    },
    minTotal() {
      return Math.min(...this.statsOnlyCompareList.map((item) => item.total));
    },
    maxTotal() {
      return Math.max(...this.statsOnlyCompareList.map((item) => item.total));
    },
    averageTotal() {
      var totals = this.statsOnlyCompareList.map((item) => item.total);
      return totals.reduce((total, value) => total + value, 0) / totals.length;
    },
    betweenMinAndAvgMark() {
      return (this.minTotal + this.averageTotal) / 2;
    },
    betweenMaxAndAvgMark() {
      return (this.maxTotal + this.averageTotal) / 2;
    },
    ...mapState([]),
    ...mapGetters([
      "getChartFontColor",
      "getChartAngleLinesColor",
      "getChartGridLinesColor",
    ]),
  },
  data() {
    return {
      selected: [],
      headers: [
        {
          text: "Image",
          align: "start",
          sortable: false,
          value: "image",
        },
        {
          text: "Name",
          align: "start",
          sortable: false,
          value: "name",
        },
        { text: "HP", value: "hp" },
        { text: "Attack", value: "attack" },
        { text: "Defense", value: "defense" },
        { text: "Speed", value: "speed" },
        { text: "Special Attack", value: "special-attack" },
        { text: "Special Defense", value: "special-defense" },
        { text: "Total", value: "total" },
      ],
      labels: [
        "hp",
        "attack",
        "defense",
        "speed",
        "special-attack",
        "special-defense",
      ],
      chartData: {
        labels: [
          "hp",
          "attack",
          "defense",
          "speed",
          "special-attack",
          "special-defense",
        ],
      },
      chartOptions: {
        responsive: true,
        maintainAspectRatio: false,
        scale: {
          ticks: {
            beginAtZero: true,
            showLabelBackdrop: false,
          },
          pointLabels: {},
          gridLines: {},
          angleLines: {},
        },
      },
    };
  },
  watch: {
    isDark(newValue, oldValue) {
      this.refreshChartOption();
    },
    selected(newValue, oldValue) {
      this.chartData = {
        labels: this.labels,
        datasets: [],
      };
      for (var i = 0; i < newValue.length; i++) {
        var index = 0;
        var data = [];
        this.labels.forEach((name) => {
          data[index] = newValue[i][name];
          index++;
        });
        this.chartData.datasets.push({
          label: newValue[i].name,
          backgroundColor: this.getRandomColorChart(30),
          data,
        });
      }
    },
  },
  created() {
    this.refreshChartOption();
  },
  methods: {
    refreshChartOption() {
      this.chartOptions.scale.ticks.fontColor = this.getChartFontColor;
      this.chartOptions.scale.pointLabels.fontColor = this.getChartFontColor;
      this.chartOptions.scale.angleLines.color = this.getChartAngleLinesColor;
      this.chartOptions.scale.gridLines.color = this.getChartGridLinesColor;
    },
    removeSelectedPokemons() {
      if (this.isRemovable) {
        this.selected.forEach((item) => {
          this.$store.commit("removeFromComparePokemons", item);
        });
        this.selected = [];
      }
    },
    getTotalColor(value) {
      if (value < this.betweenMinAndAvgMark) {
        return "error";
      } else if (value > this.betweenMaxAndAvgMark) {
        return "success";
      } else {
        return "warning";
      }
    },
    checkAlpha(alpha) {
      alpha = parseInt(alpha);
      if (alpha == NaN) {
        alpha = 255;
      }
      if (alpha < 16) {
        alpha = 16;
      }
      if (alpha > 255) {
        alpha = 255;
      }
      return alpha;
    },
    getRandomColorChart(alpha = 255) {
      alpha = this.checkAlpha(alpha);
      var color = "#";
      for (let i = 0; i < 6; i++) {
        color += Math.round(Math.random() * 16).toString(16);
      }
      return `${color}${alpha.toString(16)}`.toUpperCase();
    },
  },
};
</script>

